$columns: 12

$gutter: 2% // Must be %

// calculate the total sum of a list (context)
@function list-sum($list)
  // zero out the initial sum
  $sum: 0
  // loop through each value in the list adding it to $list-sum
  @for $i from 1 through length($list)
    $sum: $sum + nth($list, $i)
  @return $sum


// calculate the width of individual columns
@function list-column-width($location, $columns)
  // send a warning if this is used when $columns is not a list
  @if type-of($columns) != list
    @warn "The column-list-sum function requires the variable $columns to be a list."
  @else
    // divide the column from its context
    @return nth($columns, $location) / list-sum($columns)


// Calculate the width spanning multiple columns
@function column-span($span, $location: 1, $columns: $columns)

  // Equal width columns
  @if type-of($columns) == number
    @return $span * (100% / $columns)

  // Variable width columns
  @if type-of($columns) == list
    // zero out initial sum
    $sum: 0
    // from start point to end point
    @for $i from $location to ($location + $span)
      $sum: $sum + list-column-width($i, $columns)
    @return percentage($sum)


// Gutters to be subtracted from columns


// TEST

$columns: 1, 2, 4, 8, 16, 32
@debug column-span(3, 3)

// This import applies a global reset to any page that imports this stylesheet.
@import blueprint/reset
// To configure blueprint, edit the partials/base.sass file.
@import partials/base
// Import all the default blueprint modules so that we can access their mixins.
@import blueprint
// Import the non-default scaffolding module.
@import blueprint/scaffolding

// To generate css equivalent to the blueprint css but with your configuration applied, uncomment:
// +blueprint

//Recommended Blueprint configuration with scoping and semantic layout:
+blueprint-scaffolding("body.bp")
body.bp
  +blueprint-typography(true)
  +blueprint-utilities
  +blueprint-debug
  +blueprint-interaction
  // Remove the scaffolding when you're ready to start doing visual design.
  // Or leave it in if you're happy with how blueprint looks out-of-the-box
form.bp
  +blueprint-form

// Page layout can be done using mixins applied to your semantic classes and IDs:
body.two-col
  #container
    +container
  #header, #footer
    +column($blueprint-grid-columns)
  #sidebar
    // One third of the grid columns, rounding down. With 24 cols, this is 8.
    $sidebar-columns: floor($blueprint-grid-columns / 3)
    +column($sidebar-columns)
  #content
    // Two thirds of the grid columns, rounding up.
    // With 24 cols, this is 16.
    $content-columns: ceil(2 * $blueprint-grid-columns / 3)
    // true means it's the last column in the row
    +column($content-columns, true)

// This file serves as the "skeleton" of the theming logic.
//
// This contains the bulk of the logic for handling dark mode, color scheme
// toggling and the handling of color-scheme-specific hiding of elements.

@use "../variables" as *

body
  @include fonts
  @include spacing
  @include icons
  @include admonitions
  @include default-admonition(#651fff, "abstract")
  @include default-topic(#14B8A6, "pencil")

  @include colors

.only-light
  display: block !important
html body .only-dark
  display: none !important

// Ignore dark-mode hints if print media.
@media not print
  // Enable dark-mode, if requested.
  body[data-theme="dark"]
    @include colors-dark

    html & .only-light
      display: none !important
    .only-dark
      display: block !important

  // Enable dark mode, unless explicitly told to avoid.
  @media (prefers-color-scheme: dark)
    body:not([data-theme="light"])
      @include colors-dark

      html & .only-light
        display: none !important
      .only-dark
        display: block !important

//
// Theme toggle presentation
//
body[data-theme="auto"]
  .theme-toggle svg.theme-icon-when-auto-light
    display: block

  @media (prefers-color-scheme: dark)
    .theme-toggle svg.theme-icon-when-auto-dark
      display: block
    .theme-toggle svg.theme-icon-when-auto-light
      display: none

body[data-theme="dark"]
  .theme-toggle svg.theme-icon-when-dark
    display: block

body[data-theme="light"]
  .theme-toggle svg.theme-icon-when-light
    display: block

